+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const separator = line.indexOf("=");
+    if (separator === -1) throw new Error(`Invalid RC line "${rawLine}".`);
+    const key = camelCaseConfigKey(line.slice(0, separator).trim());
+    let value = line.slice(separator + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) {
+        throw new Error(`Unterminated quoted value for "${key}".`);
+      }
+      value = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      result[key] = value === "true";
+      continue;
+    } else if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+      result[key] = Number(value);
+      continue;
+    }
+    result[key] = value;
+  }
+  return result;
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [rawKey, item] of Object.entries(value)) {
+    const key = prefix
+      ? `${prefix}.${camelCaseConfigKey(rawKey)}`
+      : camelCaseConfigKey(rawKey);
+    if (isPlainObject(item)) Object.assign(result, flattenConfig(item, key));
