  await withConfig({
    "app.json": JSON.stringify({
      "dry-run": false,
      count: 0,
      "nested.value": "configured",
      tags: ["one", "two"],
      ignored: true,
    }),
  }, async (directory) => {
    const command = new Command()
      .throwErrors()
      .config({ name: "app", searchPaths: [directory] })
      .option("--dry-run", "...")
      .option("--count <count:number>", "...")
      .option("--nested.value <value>", "...")
      .option("--tags <tag>", "...", { collect: true });

    const configured = await command.parse([]);
    assertEquals(configured.options as Record<string, unknown>, {
      dryRun: false,
      count: 0,
      nested: { value: "configured" },
      tags: ["one", "two"],
    });
    assertEquals(command.getConfigPath(), `${directory}/app.json`);
    assertEquals(command.getConfigValues().count, 0);

    const overridden = await command.parse(["--count", "2"]);
    assertEquals(overridden.options.count, 2);
  });
});

